const l=JSON.parse('{"key":"v-6be3af74","path":"/posts/%E5%BC%82%E6%AD%A5%E7%BC%96%E7%A8%8B%E7%9A%84%E5%AE%9E%E7%8E%B0%E6%96%B9%E5%BC%8F.html","title":"异步编程的实现方式","lang":"zh-CN","frontmatter":{"title":"异步编程的实现方式","isTimeLine":true,"date":"2025-05-12T00:00:00.000Z","category":["前端"],"tag":["JavaScript"]},"headers":[{"level":3,"title":"同步与异步?","slug":"同步与异步","link":"#同步与异步","children":[]},{"level":3,"title":"事件循环？","slug":"事件循环","link":"#事件循环","children":[]},{"level":3,"title":"异步编程的实现方式？","slug":"异步编程的实现方式","link":"#异步编程的实现方式","children":[]},{"level":3,"title":"Promise 对象？","slug":"promise-对象","link":"#promise-对象","children":[]},{"level":3,"title":"async/await？","slug":"async-await","link":"#async-await","children":[]},{"level":3,"title":"XHR请求","slug":"xhr请求","link":"#xhr请求","children":[]},{"level":3,"title":"axios","slug":"axios","link":"#axios","children":[]},{"level":3,"title":"ajax、axios、fetch 的区别","slug":"ajax、axios、fetch-的区别","link":"#ajax、axios、fetch-的区别","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773286516000,"updatedTime":1773286516000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":6.96,"words":2089},"filePathRelative":"posts/异步编程的实现方式.md","localizedDate":"2025年5月12日","excerpt":"<h3> 同步与异步?</h3>\\n<ol>\\n<li>同步：后一个任务等待前一个任务执行完毕后再执行</li>\\n<li>异步：非阻塞的，主逻辑与异步逻辑相互独立，主逻辑不需要等待异步逻辑完成，而是可以立即执行下去</li>\\n</ol>\\n<h3> 事件循环？</h3>\\n<ol>\\n<li>JS中用来存储待执行回调函数的队列包含2个不同特定的列队</li>\\n<li>宏任务队列：用来保存待执行的宏任务（回调）比如：定时器回调/DOM事件回调/ajax回调；</li>\\n<li>微任务队列：用来保存待执行的微任务（回调）比如：promise回调/MutationObserver回调/process.nextTick；</li>\\n<li>事件循环？执行宏任务，然后执行该宏任务产生的微任务，若微任务在执行过程中产生了新的微任务，则继续执行微任务，微任务执行完毕后，再回到宏任务中进行下一轮循环。</li>\\n</ol>"}');export{l as data};
